using ContractManagement.Domain.Contracts; using Microsoft.EntityFrameworkCore; using Microsoft.EntityFrameworkCore.Metadata.Builders;
namespace ContractManagement.Infrastructure.Persistence.Configurations;
public sealed class ContractAuditLogConfiguration:IEntityTypeConfiguration<ContractAuditLog>{public void Configure(EntityTypeBuilder<ContractAuditLog>b){b.ToTable("ContractAuditLogs");b.HasKey(x=>x.Id);b.Property(x=>x.Id).ValueGeneratedOnAdd();b.Property(x=>x.Action).HasMaxLength(100).IsRequired();b.Property(x=>x.UserId).HasMaxLength(450);b.Property(x=>x.UserName).HasMaxLength(200);b.Property(x=>x.IpAddress).HasMaxLength(64);b.Property(x=>x.DeviceId).HasMaxLength(200);b.HasOne(x=>x.Contract).WithMany(x=>x.AuditLogs).HasForeignKey(x=>x.ContractId).OnDelete(DeleteBehavior.Restrict);b.HasIndex(x=>new{x.ContractId,x.CreatedAt}).IsDescending(false,true).HasDatabaseName("IX_ContractAuditLogs_Contract_CreatedAt");b.HasIndex(x=>new{x.UserId,x.CreatedAt}).IsDescending(false,true).HasDatabaseName("IX_ContractAuditLogs_User_CreatedAt");}}
